function countComponents(n: number, edges: number[][], X: number): number {

   const parent = Array(n).fill(0).map((_, i) => i);

   const rank = Array(n).fill(1);

   function find(u: number): number {

      if (parent[u] !== u) {

         parent[u] = find(parent[u]);

      }

      return parent[u];

   }

   function union(u: number, v: number): boolean {

      const rootU = find(u);

      const rootV = find(v);

      if (rootU === rootV) return false;

      if (rank[rootU] < rank[rootV]) {

         parent[rootU] = rootV;

      } else {

         parent[rootV] = rootU;

         if (rank[rootU] === rank[rootV]) {

            rank[rootU]++;

         }

      }

      return true;

   }

   for (const [u, v, w] of edges) {

      if (w <= X) {

         union(u, v);

      }

   }

   // count the number of unique roots

   const roots = new Set<number>();

   for (let i = 0; i < n; i++) {

      roots.add(find(i));

   }

   return roots.size;

}

