function solve(n: number, edges: number[][], k: number): number {
    edges.sort((a, b) => a[2] - b[2]);
    const maxW = edges[edges.length - 1][2] || 0;
    let low = 1, high = maxW;
    let answer = maxW;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const components = countComponents(n, edges, mid);
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

function countComponents(n: number, edges: number[][], X: number): number {
    const parent = Array(n).fill(0).map((_, i) => i);
    const rank = Array(n).fill(1);

    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) return false;
        if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV;
        } else {
            parent[rootV] = rootU;
            if (rank[rootU] === rank[rootV]) {
                rank[rootU]++;
            }
        }
        return true;
    }

    for (const [u, v, w] of edges) {
        if (w <= X) {
            union(u, v);
        }
    }

    const roots = new Set<number>();
    for (let i = 0; i < n; i++) {
        roots.add(find(i));
    }

    return roots.size;
}
